questionvariables.text:
/* Q1: Media Classification and Attenuation */
/* Mix of good conductors (sets 1-3) and low-loss dielectrics (sets 4-5) */
idx: 1 + rand(5);

/* [sigma_coeff, sigma_exponent, eps_r, mu_r, f_MHz, material] */
sigma_c: [5.8, 3.5, 1.0, 1.0, 1.0][idx];
sigma_e: [7, 7, 7, -3, -2][idx];
eps_r: [1, 1, 1, 10, 5][idx];
mu_r: [1, 1, 200, 1, 1][idx];
f_MHz: [100, 500, 60, 100, 1000][idx];
mat_name: ["copper", "aluminum", "iron", "dry earth", "wet wood"][idx];

sigma: sigma_c * 10^sigma_e;

/* Constants — exact arithmetic (P-STACK-06) */
mu_0: 4*%pi/10^7;
eps_0: 1/(36*%pi*10^9);

f_Hz: f_MHz * 10^6;
omega: 2*%pi * f_Hz;
mu: mu_r * mu_0;
eps: eps_r * eps_0;

/* (a) Loss tangent */
tans1: float(sigma / (omega * eps));

/* Classification flag */
is_conductor: is(tans1 > 10);

/* (b) Classification MCQ — correct answer depends on variant */
ta2: if is_conductor then
  random_permutation([
    [1, true, "Good conductor"],
    [2, false, "Low-loss dielectric"],
    [3, false, "Lossless (perfect dielectric)"]
  ])
else
  random_permutation([
    [1, false, "Good conductor"],
    [2, true, "Low-loss dielectric"],
    [3, false, "Lossless (perfect dielectric)"]
  ]);
correct_b: if is_conductor then 1 else 2;

/* (c) Attenuation constant — formula depends on classification */
alpha_val: if is_conductor then float(sqrt(%pi * f_Hz * mu * sigma))
           else float(sigma / 2 * sqrt(mu / eps));
tans3: alpha_val;

/* (d) Skin depth */
tans4: float(1 / alpha_val);

/* (e) Frequency doubling MCQ — answer depends on medium type */
ta5: if is_conductor then
  random_permutation([
    [1, true, "Increases by factor sqrt(2)"],
    [2, false, "Does not change"],
    [3, false, "Doubles"],
    [4, false, "Decreases by factor sqrt(2)"]
  ])
else
  random_permutation([
    [1, false, "Increases by factor sqrt(2)"],
    [2, true, "Does not change"],
    [3, false, "Doubles"],
    [4, false, "Decreases by factor sqrt(2)"]
  ]);
correct_e: if is_conductor then 1 else 2;

/* Error models */
/* Used wrong formula (conductor formula for low-loss or vice versa) */
alpha_cross: if is_conductor then float(sigma / 2 * sqrt(mu / eps))
             else float(sqrt(%pi * f_Hz * mu * sigma));
/* Forgot mu_r */
alpha_nomur: if is_conductor then float(sqrt(%pi * f_Hz * mu_0 * sigma))
             else float(sigma / 2 * sqrt(mu_0 / eps));

feedbackvariables.text:
/* Did student use the wrong formula? */
cross_flag: if is(abs(alpha_cross) > 0) and is(abs(ans3 - alpha_cross)/abs(alpha_cross) < 0.06) then 1 else 0;
/* Did student forget mu_r? */
mur_flag: if is(mu_r > 1) and is(abs(alpha_nomur) > 0) and is(abs(ans3 - alpha_nomur)/abs(alpha_nomur) < 0.06) then 1 else 0;
